div.p:
FOR each probe in probes[]:
IF probe->link != NULL:
bpf_link__destroy(probe->link)
// Detaches from kernel
// Closes file descriptor
// Frees link memory
probe->link = NULL
probe->status = DISABLED

// Releases ring buffer consumer
// Closes internal file descriptor
// Frees consumer structure
ring_buffer__free(rb);
rb = NULL;

// Close timer file descriptor
// Stops periodic events
close(timer_fd);
timer_fd = -1;

// Close epoll instance
// Automatically unregisters all FDs
close(epoll_fd);
epoll_fd = -1;

// Destroys BPF object and ALL maps
// Closes all map file descriptors
// Unloads programs from kernel
// Frees skeleton memory
dashboard_bpf__destroy(skel);
skel = NULL;

// Restore terminal settings
// Switch from alternate screen buffer
// Show cursor
// Re-enable line buffering
terminal_cleanup();
